var LoginPage = class extends BaseElement {
  name;
  token;
  loginButton;
  error;
  html() {
    return `<div class="login__container rsborder rsbackground">
  <men-input
    class="login__name"
    input-id="groupName"
    placeholder-text="Group name"
    input-label="Group name"
  ></men-input>
  <men-input
    class="login__token"
    max-length="60"
    input-id="groupToken"
    placeholder-text="Group token"
    input-label="Group token"
    type-password
  ></men-input>
  <button class="login__button men-button">Login</button>
  <div class="login__error validation-error"></div>
</div>
`;
  }
  connectedCallback() {
    super.connectedCallback();
    this.render();
    const name = this.querySelector(".login__name");
    const token = this.querySelector(".login__token");
    const loginButton = this.querySelector(".login__button");
    const error48 = this.querySelector(".login__error");
    if (!(name instanceof HTMLElement) || !(token instanceof HTMLElement) || !(loginButton instanceof HTMLButtonElement) || !(error48 instanceof HTMLElement)) {
      return;
    }
    this.name = name;
    this.name.validators = [(value) => validationErrorFromSchema(loginFieldSchema, value)];
    this.token = token;
    this.token.validators = [(value) => validationErrorFromSchema(loginFieldSchema, value)];
    this.loginButton = loginButton;
    this.error = error48;
    this.eventListener(this.loginButton, "click", this.login.bind(this));
  }
  async login() {
    if (!this.name.valid || !this.token.valid) {
      return;
    }
    try {
      this.error.innerHTML = "";
      this.loginButton.disabled = true;
      const name = this.name.value ?? "";
      const token = this.token.value ?? "";
      api.setCredentials(name, token);
      const response = await api.amILoggedIn();
      if (response.ok) {
        storage.storeGroup(name, token);
        window.history.pushState("", "", "/group");
      } else if (response.status === 401) {
        this.error.innerHTML = "Group name or token is incorrect";
      } else {
        const body = await response.text();
        this.error.innerHTML = `Unable to login ${body}`;
      }
    } catch (error48) {
      this.error.innerHTML = `Unable to login ${error48}`;
    } finally {
      this.loginButton.disabled = false;
    }
  }
};
customElements.define("login-page", LoginPage);

