function getLevelForXp(xp) {
  for (let i = XP_TABLE.length - 1; i >= 1; i--) {
    if (xp >= XP_TABLE[i]) return i;
  }
  return 1;
}
function getActivitiesForItem(experienceItemName) {
  return ACTIVITIES.filter((activity) => activity.experienceItem === experienceItemName);
}
function getExperienceItemsForSkill(skill) {
  return Object.values(EXPERIENCE_ITEMS).filter((item) => item.skill === skill);
}

